(()=>{
  "use strict";

  const formatNumber=(value)=>new Intl.NumberFormat("en-US").format(value);

  const animateCountUp=(element,duration=4000)=>{
    const raw=(element.textContent||"").replace(/,/g,"").trim();
    const target=Number.parseInt(raw,10);
    if(!Number.isFinite(target))return;

    const start=performance.now();
    const easeOutQuad=(t)=>t*(2-t);

    const frame=(now)=>{
      const progress=Math.min((now-start)/duration,1);
      const current=Math.round(target*easeOutQuad(progress));
      element.textContent=progress===1?formatNumber(target):String(current);
      if(progress<1)window.requestAnimationFrame(frame);
    };

    window.requestAnimationFrame(frame);
  };

  const animateSelector=(selector)=>{
    document.querySelectorAll(selector).forEach((element)=>animateCountUp(element));
  };

  const animateCommaCounters=()=>{
    document.querySelectorAll(".counter").forEach((counter)=>{
      const raw=(counter.textContent||"").replace(/[^\d.-]/g,"");
      const target=Number(raw);
      if(!Number.isFinite(target))return;

      const start=performance.now();
      counter.textContent="0";

      const frame=(now)=>{
        const progress=Math.min((now-start)/700,1);
        counter.textContent=formatNumber(Math.ceil(target*progress));
        if(progress<1)window.requestAnimationFrame(frame);
      };

      window.requestAnimationFrame(frame);
    });
  };

  const observeOnce=(element,callback)=>{
    if(!element)return;
    if(!("IntersectionObserver" in window)){
      callback();
      return;
    }

    const observer=new IntersectionObserver((entries)=>{
      if(entries.some((entry)=>entry.isIntersecting)){
        callback();
        observer.disconnect();
      }
    });

    observer.observe(element);
  };

  const initializeCounters=()=>{
    observeOnce(document.querySelector(".stats-section"),()=>{
      animateSelector(".countup");
      animateCommaCounters();
    });

    observeOnce(document.querySelector(".service-area"),()=>{
      animateSelector(".countup2");
    });
  };

  const initializeModal=()=>{
    const modal=document.getElementById("modal-1");
    if(!modal)return;

    const closeButton=modal.querySelector(".modal-close-1");
    const repeatInterval=14*24*60*60*1000;
    const now=Date.now();
    let lastShown=0;

    try{
      lastShown=Number.parseInt(localStorage.getItem("modal1LastShown")||"0",10);
    }catch(error){
      lastShown=0;
    }

    const shouldShow=!Number.isFinite(lastShown)||!lastShown||now-lastShown>repeatInterval;
    modal.style.display=shouldShow?"block":"none";
    modal.style.visibility=shouldShow?"visible":"hidden";

    if(shouldShow){
      try{
        localStorage.setItem("modal1LastShown",String(now));
      }catch(error){
        // Continue without persistence when storage is unavailable.
      }
    }

    if(closeButton){
      closeButton.addEventListener("click",()=>{
        modal.style.display="none";
        modal.style.visibility="hidden";
      });
    }
  };

  const initializeStickyBanner=()=>{
    const banner=document.querySelector(".worldcup-banner");
    if(!banner)return;

    const update=()=>{
      banner.classList.toggle("is-sticky",window.innerWidth>479);
    };

    update();
    window.addEventListener("resize",update,{passive:true});
  };

  const initializeFadeElements=()=>{
    const elements=document.querySelectorAll(".fade-in");
    if(!elements.length)return;

    if(!("IntersectionObserver" in window)){
      elements.forEach((element)=>element.classList.add("fade-in-active"));
      return;
    }

    const observer=new IntersectionObserver((entries)=>{
      entries.filter((entry)=>entry.isIntersecting).forEach((entry,index)=>{
        window.setTimeout(()=>{
          entry.target.classList.add("fade-in-active");
        },index*30);
        observer.unobserve(entry.target);
      });
    },{
      threshold:0,
      rootMargin:"0px 0px -100px 0px"
    });

    elements.forEach((element)=>observer.observe(element));
  };

  const mountSplide=(selector,options)=>{
    if(typeof window.Splide!=="function")return;

    document.querySelectorAll(selector).forEach((element)=>{
      if(element.dataset.splideMounted==="true")return;
      new window.Splide(element,options).mount();
      element.dataset.splideMounted="true";
    });
  };

  const initializeSplideSliders=()=>{
    mountSplide(".slider1",{
      type:"fade",
      arrows:true,
      speed:600,
      autoWidth:false,
      rewind:true,
      rewindSpeed:400,
      waitForTransition:false,
      updateOnMove:true,
      trimSpace:false,
      classes:{pagination:"splide__pagination how-we-do-it-pagination"},
      breakpoints:{991:{},767:{},479:{}}
    });

    mountSplide(".slider2",{
      type:"loop",
      drag:true,
      snap:true,
      perPage:3,
      focus:0,
      breakpoints:{
        991:{perPage:2},
        767:{perPage:1,padding:"24px"},
        479:{}
      }
    });

    mountSplide(".slider3",{
      type:"loop",
      drag:true,
      snap:true,
      speed:600,
      rewind:true,
      rewindSpeed:400,
      breakpoints:{
        991:{},
        767:{padding:"32px",gap:"12px"},
        479:{padding:"16px"}
      }
    });

    mountSplide(".slider4",{
      type:"loop",
      drag:"free",
      snap:true,
      pagination:false,
      perPage:4,
      perMove:1,
      gap:"16px",
      breakpoints:{
        991:{perPage:3},
        767:{perPage:2,padding:"24px"},
        479:{perPage:1}
      }
    });
  };

  const initializeReviewSchema=()=>{
    document.querySelectorAll(".review-schema").forEach((item)=>{
      const author=(item.dataset.author||"").trim();
      const reviewBody=(item.dataset.review||"").trim();
      if(!author||!reviewBody)return;

      const review={
        "@context":"https://schema.org",
        "@type":"Review",
        itemReviewed:{"@type":"Organization",name:"Savoya"},
        author:{"@type":"Person",name:author},
        reviewBody
      };

      const script=document.createElement("script");
      script.type="application/ld+json";
      script.textContent=JSON.stringify(review);
      document.head.appendChild(script);
    });
  };

  const initializeHomepage=()=>{
    initializeModal();
    initializeStickyBanner();
    initializeFadeElements();
    initializeCounters();
    initializeSplideSliders();
    initializeReviewSchema();
  };

  if(document.readyState==="loading"){
    document.addEventListener("DOMContentLoaded",initializeHomepage,{once:true});
  }else{
    initializeHomepage();
  }
})();

